#define WG_SIZE_X (64)
#define WG_SIZE_Y (4)
#define AMB_TEMP 80.0f

__kernel void hotspotOpt1(
    __global const float *pIn,
    __global const float *tIn,
    __global float *tOut,
    float stepDivCap,
    int nx,
    int ny,
    int nz,
    float ce,
    float cw,
    float cn,
    float cs,
    float ct,
    float cb,
    float cc)
{
    int x = get_global_id(0);
    int y = get_global_id(1);

    if (x >= nx || y >= ny) {
        return;
    }

    int base_index = x + y * nx;

    for (int z = 0; z < nz; z++) {
        int c = base_index + z * nx * ny;

        int w = (x == 0) ? c : c - 1;
        int e = (x == nx - 1) ? c : c + 1;
        int n = (y == 0) ? c : c - nx;
        int s = (y == ny - 1) ? c : c + nx;
        int b = (z == 0) ? c : c - nx * ny;
        int t_idx = (z == nz - 1) ? c : c + nx * ny;

        tOut[c] = cc * tIn[c] + cw * tIn[w] + ce * tIn[e]
                  + cs * tIn[s] + cn * tIn[n] + cb * tIn[b] + ct * tIn[t_idx]
                  + stepDivCap * pIn[c] + ct * AMB_TEMP;
    }
}
